import{_ as e,o as t,c as a,a2 as d}from"./chunks/framework.C24VBsJ9.js";const B=JSON.parse('{"title":"什么是 U-Boot","description":"","frontmatter":{"title":"什么是 U-Boot"},"headers":[],"relativePath":"tutorial/uboot/01_what_is_uboot.md","filePath":"tutorial/uboot/01_what_is_uboot.md","lastUpdated":1781369075000}'),c={name:"tutorial/uboot/01_what_is_uboot.md"};function i(r,o,p,u,n,s){return t(),a("div",null,[...o[0]||(o[0]=[d('<h1 id="从0开始理解-u-boot-嵌入式系统的-第一道门-以及我们为什么终于告别了硬编码时代" tabindex="-1">从0开始理解 U-Boot：嵌入式系统的&quot;第一道门&quot;，以及我们为什么终于告别了硬编码时代 <a class="header-anchor" href="#从0开始理解-u-boot-嵌入式系统的-第一道门-以及我们为什么终于告别了硬编码时代" aria-label="Permalink to &quot;从0开始理解 U-Boot：嵌入式系统的&quot;第一道门&quot;，以及我们为什么终于告别了硬编码时代&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">本节你将学到</p><ul><li>U-Boot 在 i.MX6ULL 启动链路中的位置与职责</li><li>从 ROM Code → U-Boot → Linux 内核 的完整交接过程</li><li>U-Boot 从「硬编码」到「设备树」时代的演进逻辑</li></ul></div><div class="tip custom-block"><p class="custom-block-title">前置知识 · 环境</p><ul><li>了解嵌入式 Linux 的整体启动链条（见 <a href="./../start/00_roadmap">学习路线图</a>）</li><li>工具链已就绪（见 <a href="./../start/01_start_from_toolchain">工具链安装</a>）</li></ul></div><h2 id="为什么要写这篇文章" tabindex="-1">为什么要写这篇文章 <a class="header-anchor" href="#为什么要写这篇文章" aria-label="Permalink to &quot;为什么要写这篇文章&quot;">​</a></h2><p>笔者是2025年开始的嵌入式Linux的研究的，好在之前Linux的使用经验也稍微有一些，开发经验多少有那么一点，所以还好，对我而言学习曲线尚可。</p><p>但是这个尚可对我还是有点难度的——当我第一次拿到 i.MX6ULL 这块板子的时候，我是真的懵了。完全就只会插个电源，拨个开关然后对着日志发呆。</p><p>UBoot的日志就是我们日志的起点，相信你可以猜到，UBoot就是板子交接的第一个棒。是的——引导加载程序。</p><p>你可能会说，不就是个引导加载程序嘛，网上教程一堆，照着敲命令不就行了？问题就在这里——网上的教程确实不少，但要么是几年前的老版本，要么就是只给你一堆命令却不告诉你为什么这么敲。我当时折腾了整整一天，踩了各种坑：工具链版本不对、设备树选错了、编译产物验证不过，最离谱的是有一次因为 .config 残留导致改了配置完全不生效，排查到半夜看到我靠怎么还是你发现.config的时间戳不对想把地球炸了（这件事情告诉我们勤快的清理是必要的）</p><p>是的！都 2026 年了，我们还在用一套诞生于 20 世纪末的引导加载程序。这倒不是说它过时，恰恰相反，U-Boot 之所以能活到现在，是因为它在不断地进化。但问题在于，它的文档太分散了，官方文档写得像技术规范书，新手看了直摇头；社区教程又良莠不齐，很多还是基于 2010 年代的经验写的。</p><p>所以我决定写这篇文章，不是为了给你一个&quot;复制粘贴就能用&quot;的脚本——那个东西我最后会给你——而是想带你完整地走一遍 U-Boot 的来龙去脉。当你理解了它是什么、为什么存在、它是如何从硬编码时代进化到设备树时代的，你会发现，所谓的&quot;黑魔法&quot;其实都有清晰的逻辑。</p><h2 id="u-boot-到底是什么" tabindex="-1">U-Boot 到底是什么 <a class="header-anchor" href="#u-boot-到底是什么" aria-label="Permalink to &quot;U-Boot 到底是什么&quot;">​</a></h2><p>如果非要用一个类比来解释 U-Boot，我会说它就像是电脑的 BIOS，但比 BIOS 强大得多。</p><p>在一台 x86 电脑上，当你按下电源键，首先运行的是主板上的 BIOS/UEFI，它负责初始化硬件、加载操作系统。嵌入式系统的启动流程类似，但更加复杂：芯片内部的 ROM Code 会先运行一段厂商写死的代码（嗯。。。一些厂商会在里面加点小料的），这段代码会从外部存储介质（eMMC、SD 卡、SPI Flash）中加载 U-Boot，然后 U-Boot 接管控制权，完成更复杂的硬件初始化，最后加载 Linux 内核。</p><p>所以 U-Boot 在启动链条中的位置是这样的：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ROM Code → U-Boot → Linux Kernel → Rootfs</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>那为什么不能让 ROM Code 直接加载 Linux 内核呢？原因很简单：ROM 代码的空间极其有限，而且它是厂商写死的，你改不了。Linux 内核需要知道板子上有哪些硬件、内存地址是什么、外设怎么初始化，这些东西 ROM 代码搞不定，必须由一个可编程的中间层来完成——这就是 U-Boot 存在的意义。</p><p>具体来说，U-Boot 要做这几件事：初始化 DDR 内存、初始化存储设备（eMMC、SD 卡）、从存储设备中加载设备树和内核镜像、把设备树地址和内核入口地址告诉 CPU、最后跳转到内核启动。它还提供了一个交互式命令行，你可以在启动前手动修改环境变量、加载文件、网络启动等等。这部分功能在实际调试中简直救命。</p><h2 id="从-8xxrom-到-das-u-boot-二十多年的进化史" tabindex="-1">从 8xxROM 到 Das U-Boot：二十多年的进化史 <a class="header-anchor" href="#从-8xxrom-到-das-u-boot-二十多年的进化史" aria-label="Permalink to &quot;从 8xxROM 到 Das U-Boot：二十多年的进化史&quot;">​</a></h2><p>U-Boot 的历史比很多人想象的要长得多。它的前身可以追溯到 1999 年之前的 8xxROM，那是 Magnus Damm 为 PowerPC 8xx 系列处理器写的一个个人项目。当时的嵌入式引导加载程序基本是&quot;一板一代码&quot;，换一块板子就要重写一套。</p><p>1999 年 10 月，德国 DENX 软件工程中心的 Wolfgang Denk 接手了这个项目，把它搬到了 SourceForge 上。但 SourceForge 不允许用 &quot;8xxROM&quot; 这个名字，所以改名叫 PPCBoot——你看得出来，这是 PowerPC Boot Loader 的缩写。这个时期 PPCBoot 主要是为 PowerPC 处理器服务的，架构支持相对单一。</p><p>事情在 2002 年发生了转折。当时有一个叫 ARMBoot 的项目，是 PPCBoot 的 ARM 架构移植版本。大家觉得维护两个重复的项目没意义，于是决定合并。2002 年 7 月开始合并工作，2002 年 11 月发布了 PPCBoot 的最后一个版本 2.0.0（代号&quot;Halloween Release&quot;），然后同年 12 月 17 日，第一个名为 &quot;U-Boot&quot; 的版本 0.2.0 诞生了。&quot;Das U-Boot&quot; 是德语，&quot;Das&quot; 是定冠词，&quot;U-Boot&quot; 是 &quot;Universal Boot Loader&quot; 的缩写——通用引导加载程序。从那以后，PPCBoot 和 ARMBoot 项目停止维护，统一到 U-Boot。</p><p>版本命名也经历了变化。2008 年之前，U-Boot 用的是传统数字版本号，比如 1.1.3、1.3.4。但从 2008 年 10 月开始，版本号改成了基于时间的格式，类似 Ubuntu：v2009.11 表示 2009 年 11 月发布，v2009.11.1 是这个版本的 bug 修复版。这个命名规则一直沿用到现在，最新版本是 v2026.01，每三个月发布一次。</p><h2 id="设备树革命-为什么我们终于告别了硬编码" tabindex="-1">设备树革命：为什么我们终于告别了硬编码 <a class="header-anchor" href="#设备树革命-为什么我们终于告别了硬编码" aria-label="Permalink to &quot;设备树革命：为什么我们终于告别了硬编码&quot;">​</a></h2><p>说到 U-Boot 的进化，最彻底的改变莫过于设备树的引入。在设备树出现之前，嵌入式系统是怎么描述硬件的呢？答案是：硬编码在代码里。</p><p>你可能会问，这有什么问题？问题大了。想象一下，你的板子上有三个 I2C 设备，地址分别是 0x50、0x51、0x52。在硬编码时代，这些地址要写在板级初始化代码里。如果你想改其中一个地址，或者你想给同一款芯片换一个不同容量的 eMMC，对不起，你得重新编译整个内核。更惨的是，如果你要维护同一款芯片的十种不同板型，你就得维护十份几乎完全重复的代码，只有几个参数不同。</p><p>ARM Linux 早期使用的是 ATAG 机制——参数标签列表。这是一种在启动时向内核传递参数的方式，但功能非常有限，基本上只能传内存大小、命令行参数这些基础信息。复杂的硬件描述根本搞不定。</p><p>2008 年，PowerPC 架构已经成功迁移到了设备树机制，效果很好。2010 年，PowerPC 维护者 Grant Likely 提议 ARM 也跟进，从 ATAG 转向设备树描述硬件。这在当时引起了不小的争议，因为这意味着要改动大量的板级代码。但历史证明，这个决定是正确的。2011 到 2012 年间，ARM Linux 开始大规模迁移到设备树，ATAG 机制逐步被废弃。</p><p>设备树的核心思想很简单：把硬件描述从代码中分离出来，用一种专门的格式（DTS 文件）来描述。硬件不变，设备树就不变；硬件变了，只需要改设备树，不需要改代码。同一个内核镜像，配上不同的设备树，就可以运行在不同的板子上——这在以前是不可想象的。</p><p>U-Boot 对设备树的支持是从 v1.1.3 开始的，通过 CONFIG_OF_LIBFDT 选项启用。但有趣的是，U-Boot 和 Linux 在设备树方面并不是完全同步的。某些板级绑定在两个项目中仍然存在差异，为了解决这个问题，U-Boot 维护了一个从 Linux 内核同步的设备树子目录，通过 devicetree-rebasing 机制保持更新。你在 U-Boot 源码里看到的 <code>*-u-boot.dtsi</code> 文件，就是专门用来添加 U-Boot 特定配置的，不会和 Linux 内核的设备树冲突。</p><h2 id="u-boot-项目目录结构-代码都放在哪" tabindex="-1">U-Boot 项目目录结构：代码都放在哪 <a class="header-anchor" href="#u-boot-项目目录结构-代码都放在哪" aria-label="Permalink to &quot;U-Boot 项目目录结构：代码都放在哪&quot;">​</a></h2><p>现在我们来看看 U-Boot 的源码结构。当你第一次解压 U-Boot 源码包，你会发现目录挺多的，不知道从哪下手。其实核心目录就那么几个，其他的都是辅助性的。</p><p><code>arch/</code> 目录是架构相关的代码。对于 ARM 平台，我们主要看 <code>arch/arm/</code>。这里面 <code>cpu/</code> 存放 CPU 相关的初始化代码，<code>mach-imx/</code> 是 NXP i.MX 系列处理器的专用代码，里面按代数分了 <code>mx3/</code>、<code>mx5/</code>、<code>mx6/</code>、<code>mx7/</code>，以及更新的 <code>imx8/</code>、<code>imx8m/</code>、<code>imx8ulp/</code>、<code>imx9/</code>。<code>dts/</code> 存放设备树源文件，<code>include/</code> 是架构相关的头文件。</p><p><code>board/</code> 目录是板级支持包，里面按厂商和板型分类。比如 <code>freescale/</code> 下是 NXP 官方开发板的代码，<code>boundary/</code>、<code>engicam/</code>、<code>phytec/</code> 则是其他厂商的板子。这个目录在设备树普及之前非常重要，现在的作用已经弱化了。</p><p><code>cmd/</code> 目录实现了 U-Boot 的命令行命令。你可以在 U-Boot 命令行里敲 <code>boot</code>、<code>bdinfo</code>、<code>bootm</code>、<code>bootefi</code> 这些命令，它们的实现代码就在这里。如果你需要添加自定义命令，也要在这个目录下添加。</p><p><code>common/</code> 目录是各架构通用的功能代码，包括环境变量处理、内存管理、设备初始化等。<code>drivers/</code> 目录按设备类型组织驱动：<code>clk/</code> 是时钟驱动，<code>gpio/</code> 是 GPIO，<code>mmc/</code> 是 eMMC/SD 卡，<code>spi/</code>、<code>i2c/</code>、<code>uart/</code> 顾名思义，<code>net/</code> 在这里是以太网驱动，<code>display/</code> 是显示相关。</p><p><code>configs/</code> 目录可能对你来说最实用——里面存放了 500 多个 defconfig 文件。命名规则一般是 <code>平台_板型_功能_defconfig</code>，比如 <code>imx8mm_evk_defconfig</code> 就是 i.MX8MM EVK 开发板的配置。<code>android_gbl</code> 这种带特殊前缀的是 Android 相关配置，还有带 <code>secure</code> 的是安全启动相关。</p><p><code>dts/</code> 目录存放设备树源文件。<code>fs/</code> 是文件系统支持，包括 FAT、EXT4、UBIFS 等。<code>include/</code> 是全局头文件，<code>lib/</code> 是通用库函数，<code>net/</code> 是网络协议栈（以太网、DHCP、TFTP、DNS）。<code>scripts/</code> 是构建脚本和配置工具，<code>tools/</code> 则是各种辅助工具，比如我们后面会用到的 <code>mkimage</code>。</p><h2 id="_2025-2026-年的-u-boot-老项目的新活力" tabindex="-1">2025-2026 年的 U-Boot：老项目的新活力 <a class="header-anchor" href="#_2025-2026-年的-u-boot-老项目的新活力" aria-label="Permalink to &quot;2025-2026 年的 U-Boot：老项目的新活力&quot;">​</a></h2><p>你可能会想，U-Boot 这么老的项目，现在还有人维护吗？答案是肯定的，而且很活跃。</p><p>U-Boot 采用固定的三个月发布周期，非常可预测。发布后约 21 天是合并窗口，之后进入 RC 阶段主要修复 bug。最新版本是 2026 年 1 月 5 日发布的 v2026.01，往前是 v2025.10、v2025.07、v2025.04——我们的项目就是基于 v2025.04 的 NXP 分支。</p><p>2025 年的版本带来了不少新特性。v2025.07 增加了 Apple M1/M2 SoC 支持，改进了 NXP i.MX8/i.MX9 处理器的支持，还增强了 AMD Versal 平台和 Raspberry Pi 的支持。Python 工具也得到了改进，代码清理和功能增强一直在进行。</p><p>对于 NXP i.MX 系列的用户来说，NXP 维护了一个专门的仓库 <code>nxp-imx/uboot-imx</code>，针对 i.MX 处理器做了专门优化。i.MX6 系列相对成熟，SPL 支持和 HAB（High Assurance Boot）安全启动都有。i.MX8/i.MX8X 系列启动架构更复杂，需要 SCU（System Controller Unit）和 SCFW 固件参与。i.MX8M 和 i.MX9 系列支持 Falcon Mode 快速启动，可以直接跳转到内核或通过 ATF 跳转到 U-Boot。</p><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>到这里，你应该对 U-Boot 有了一个整体的认识。它不是一个简单的&quot;启动程序&quot;，而是一个经历了二十多年进化的复杂系统。从早期的一板一代码，到设备树带来的硬件描述分离，从单一的架构支持到现在的多平台覆盖，U-Boot 的进化史其实就是嵌入式 Linux 发展史的一个缩影。</p><p>下一篇文章，我们来深入到 U-Boot 的编译过程中。你会看到依赖包为什么必须装、交叉编译是怎么回事、defconfig 和 .config 有什么区别、编译出来的各种产物都是干什么用的。更重要的是，你会明白每一行命令背后的原因，而不是机械地复制粘贴。</p><p>准备好了吗？我们开始动手编译。</p>',46)])])}const h=e(c,[["render",i]]);export{B as __pageData,h as default};
